9	function formatRelativeDate(ts) {
10	  const now = Date.now();
11	  const diff = now - ts;
12	  const mins = Math.floor(diff / 60000);
13	  const hours = Math.floor(diff / 3600000);
14	  const days = Math.floor(diff / 86400000);
15	
16	  if (mins < 1) return 'Just now';
17	  if (mins < 60) return `${mins}m ago`;
18	  if (hours < 24) return `${hours}h ago`;
19	  if (days < 7) return `${days}d ago`;
20	  return new Date(ts).toLocaleDateString();
21	}
22	
23	function groupByDate(notifications) {
24	  const groups = {};
25	  for (const n of notifications) {
26	    const ts = n.createdAt || n.timestamp || 0;
27	    const d = new Date(ts);
28	    const today = new Date();
29	    const yesterday = new Date(today);
30	    yesterday.setDate(yesterday.getDate() - 1);
31	
32	    let label;
33	    if (d.toDateString() === today.toDateString()) {
34	      label = 'Today';
35	    } else if (d.toDateString() === yesterday.toDateString()) {
36	      label = 'Yesterday';
37	    } else {
38	      label = d.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' });
39	    }
40	
41	    if (!groups[label]) groups[label] = [];
42	    groups[label].push(n);
43	  }
44	  return groups;
45	}
