47	export async function renderNotifications(container) {
48	  if (!await requireAuth()) return;
49	  const user = getCurrentUser();
50	  const isAdmin = hasRole(['admin']);
51	
52	  let notifications = isAdmin
53	    ? await getUserNotifications()
54	    : await getUserNotifications(user.id);
55	
56	  notifications.sort((a, b) => (b.createdAt || b.timestamp || 0) - (a.createdAt || a.timestamp || 0));
57	
58	  const unreadCount = notifications.filter(n => !n.read).length;
59	
60	  container.innerHTML = `
61	    <div class="view-header">
62	      <h1>Notifications${unreadCount > 0 ? ` <span class="notification-badge">${unreadCount}</span>` : ''}</h1>
63	      <div>
64	        <button class="btn btn-secondary" id="retry-failed-btn">Retry Failed</button>
65	        <button class="btn btn-secondary" id="mark-all-read">Mark All Read</button>
66	        <button class="btn btn-danger" id="clear-all-notif">Clear All</button>
67	      </div>
68	    </div>
69	    <div class="filters">
70	      <select id="notif-status-filter" class="input">
71	        <option value="">All</option>
72	        <option value="delivered">Delivered</option>
73	        <option value="pending">Pending</option>
74	        <option value="failed">Failed</option>
75	      </select>
76	      <select id="notif-type-filter" class="input">
77	        <option value="">All Types</option>
78	        <option value="info">Info</option>
79	        <option value="success">Success</option>
80	        <option value="warning">Warning</option>
81	        <option value="error">Error</option>
82	      </select>
83	    </div>
84	    <div id="notifications-inbox"></div>
85	  `;
86	
87	  let filtered = notifications;
88	
89	  function renderInbox(items) {
90	    const inbox = document.getElementById('notifications-inbox');
91	
92	    if (items.length === 0) {
93	      inbox.innerHTML = '<div class="inbox-empty"><p>Your inbox is empty</p></div>';
94	      return;
95	    }
96	
97	    const groups = groupByDate(items);
98	    let html = '';
99	
100	    for (const [label, group] of Object.entries(groups)) {
101	      html += `<div class="inbox-group">
102	        <div class="inbox-group-header">${label}</div>`;
103	
104	      for (const n of group) {
105	        const unreadClass = n.read ? '' : ' inbox-item-unread';
106	        const typeBadge = `<span class="badge badge-${n.type || 'info'}">${n.type || 'info'}</span>`;
107	        const deliveryBadge = n.status === 'failed'
108	          ? ' <span class="badge badge-denied">failed</span>'
109	          : n.status === 'pending'
110	            ? ' <span class="badge badge-pending">pending</span>'
111	            : '';
112	        const timeStr = formatRelativeDate(n.createdAt || n.timestamp || 0);
113	
114	        html += `
115	          <div class="inbox-item${unreadClass}" data-id="${n.id}">
116	            <div class="inbox-item-indicator">
117	              ${n.read ? '' : '<span class="unread-dot"></span>'}
118	            </div>
119	            <div class="inbox-item-content">
120	              <div class="inbox-item-header">
121	                ${typeBadge}${deliveryBadge}
122	                <span class="inbox-item-time">${timeStr}</span>
123	              </div>
124	              <div class="inbox-item-message">${escapeHTML(n.message || n.templateId || '')}</div>
125	            </div>
126	            <div class="inbox-item-actions">
127	              ${!n.read ? `<button class="btn btn-sm" data-action="read" data-id="${n.id}" title="Mark as read">Mark Read</button>` : ''}
128	              <button class="btn btn-sm btn-danger" data-action="delete" data-id="${n.id}" title="Delete">Delete</button>
129	            </div>
130	          </div>`;
131	      }
132	
133	      html += '</div>';
134	    }
135	
136	    inbox.innerHTML = html;
137	    bindActions();
138	  }
139	
140	  renderInbox(filtered);
141	
142	  document.getElementById('notif-status-filter').addEventListener('change', (e) => {
143	    const s = e.target.value;
144	    filtered = s ? notifications.filter(n => n.status === s) : notifications;
145	    applyTypeFilter();
146	  });
147	
148	  document.getElementById('notif-type-filter').addEventListener('change', () => {
149	    applyTypeFilter();
150	  });
151	
152	  function applyTypeFilter() {
153	    const s = document.getElementById('notif-status-filter').value;
154	    const t = document.getElementById('notif-type-filter').value;
155	    let result = notifications;
156	    if (s) result = result.filter(n => n.status === s);
157	    if (t) result = result.filter(n => n.type === t);
158	    filtered = result;
159	    renderInbox(filtered);
160	  }
161	
162	  document.getElementById('retry-failed-btn').addEventListener('click', async () => {
163	    const results = await retryFailedNotifications();
164	    showNotification(`Retried ${results.length} notification(s)`, 'info');
165	    renderNotifications(container);
166	  });
167	
168	  document.getElementById('mark-all-read').addEventListener('click', async () => {
169	    for (const n of notifications) {
170	      if (!n.read) { n.read = true; await DB.put('notifications', n); }
171	    }
172	    showNotification('All marked as read', 'success');
173	    renderNotifications(container);
174	  });
175	
176	  document.getElementById('clear-all-notif').addEventListener('click', async () => {
177	    if (isAdmin) {
178	      // Admin can clear all notifications
179	      await DB.clear('notifications');
180	    } else {
181	      // Non-admin: only delete own notifications
182	      for (const n of notifications) {
183	        await DB.remove('notifications', n.id);
184	      }
185	    }
186	    showNotification('Notifications cleared', 'success');
187	    renderNotifications(container);
188	  });
189	
190	  function bindActions() {
191	    document.querySelectorAll('[data-action="read"]').forEach(btn => {
192	      btn.addEventListener('click', async () => {
193	        const n = await DB.get('notifications', Number(btn.dataset.id));
194	        // Only allow marking own notifications as read
195	        if (n && (isAdmin || n.userId === user.id)) {
196	          n.read = true;
197	          await DB.put('notifications', n);
198	          renderNotifications(container);
199	        }
200	      });
201	    });
202	
203	    document.querySelectorAll('[data-action="delete"]').forEach(btn => {
204	      btn.addEventListener('click', async () => {
205	        const n = await DB.get('notifications', Number(btn.dataset.id));
206	        // Only allow deleting own notifications
207	        if (n && (isAdmin || n.userId === user.id)) {
208	          await DB.remove('notifications', n.id);
209	          renderNotifications(container);
210	        }
211	      });
212	    });
213	  }
214	}
