1	/**
2	 * Notification service.
3	 * - Templates with variables: {reservationId}, {doorName}, etc.
4	 * - Scheduled reminders: 24h and 1h before reservation start
5	 * - Local retry: up to 3 attempts
6	 * - Delivered/failed receipts
7	 */
8	import DB from '../database.js';
9	import {
10	  resolveTemplate,
11	  createNotificationObject,
12	  applyDelivery,
13	  applyFailedDelivery,
14	  TEMPLATES,
15	  MAX_RETRIES
16	} from '../lib/notification-logic.js';
17	
18	// Re-export pure functions
19	export { resolveTemplate } from '../lib/notification-logic.js';
20	
21	export async function createNotification({ userId, templateId, variables, type = 'info', scheduledFor = null }) {
22	  const notification = createNotificationObject({ userId, templateId, variables, type, scheduledFor });
23	
24	  const id = await DB.add('notifications', notification);
25	  notification.id = id;
26	
27	  // Attempt immediate delivery if not scheduled in future
28	  if (!scheduledFor || scheduledFor <= Date.now()) {
29	    return deliverNotification(notification);
30	  }
31	
32	  return notification;
33	}
34	
35	export async function deliverNotification(notification) {
36	  try {
37	    applyDelivery(notification);
38	    await DB.put('notifications', notification);
39	    return notification;
40	  } catch (err) {
41	    applyFailedDelivery(notification);
42	    try { await DB.put('notifications', notification); } catch {}
43	    return notification;
44	  }
45	}
46	
47	export async function retryFailedNotifications() {
48	  const all = await DB.getAll('notifications');
49	  // Retryable: notifications that failed delivery but haven't exhausted retries.
50	  // applyFailedDelivery increments retryCount and only sets status='failed' at MAX_RETRIES,
51	  // so retryable notifications are still 'pending' with retryCount > 0 and < MAX_RETRIES.
52	  const retryable = all.filter(n => n.status === 'pending' && n.retryCount > 0 && n.retryCount < MAX_RETRIES);
53	  const results = [];
54	
55	  for (const n of retryable) {
56	    const result = await deliverNotification(n);
57	    results.push(result);
58	  }
59	
60	  return results;
61	}
62	
63	export async function processScheduledNotifications() {
64	  const all = await DB.getAll('notifications');
65	  const now = Date.now();
66	  const due = all.filter(n => n.status === 'pending' && n.scheduledFor && n.scheduledFor <= now);
67	
68	  for (const n of due) {
69	    await deliverNotification(n);
70	  }
71	
72	  return due.length;
73	}
