75	export async function scheduleReservationReminders(reservation) {
76	  const startTime = new Date(`${reservation.date}T${reservation.time}`).getTime();
77	
78	  // 24h reminder
79	  const reminder24h = startTime - 24 * 60 * 60 * 1000;
80	  if (reminder24h > Date.now()) {
81	    await createNotification({
82	      userId: reservation.userId,
83	      templateId: 'reservation_reminder_24h',
84	      variables: { reservationId: reservation.id, zone: reservation.zone },
85	      type: 'info',
86	      scheduledFor: reminder24h
87	    });
88	  }
89	
90	  // 1h reminder
91	  const reminder1h = startTime - 60 * 60 * 1000;
92	  if (reminder1h > Date.now()) {
93	    await createNotification({
94	      userId: reservation.userId,
95	      templateId: 'reservation_reminder_1h',
96	      variables: { reservationId: reservation.id, zone: reservation.zone },
97	      type: 'warning',
98	      scheduledFor: reminder1h
99	    });
100	  }
101	}
102	
103	export function getTemplates() {
104	  return { ...TEMPLATES };
105	}
106	
107	export async function getUserNotifications(userId) {
108	  if (userId) {
109	    return DB.getByIndex('notifications', 'userId', userId);
110	  }
111	  return DB.getAll('notifications');
112	}
