4	/**
5	 * Object-level authorization tests.
6	 *
7	 * The service layer enforces ownership and role checks at the object level:
8	 *   - permissions.consumeEntry: only owner / operator / admin may consume
9	 *   - permissions.getPermissionsForReservation: only owner / operator / admin
10	 *   - notifications.getUserNotifications: userId scoping
11	 *   - auth-service.registerWithRole: only admin actor allowed
12	 *
13	 * Since the service modules depend on IndexedDB, we test the authorization
14	 * decision logic in isolation by replicating the guard conditions.
15	 */
16	
17	import { hasPermissionForRole } from '../frontend/js/lib/auth-logic.js';
18	
19	// --------------------------------------------------------------------------
20	// Helpers — replicate the object-level guard logic from the service modules
21	// so we can unit-test the authorization decisions without IndexedDB.
22	// --------------------------------------------------------------------------
23	
24	/**
25	 * Mirrors permissions.js:consumeEntry authorization check (lines 47-51).
26	 * Returns true if actor is authorized to consume the given permission.
27	 */
28	function isAuthorizedToConsume(permission, actor) {
29	  if (!actor) return false;
30	  const isOwner = permission.userId === actor.id;
31	  const isPrivileged = actor.role === 'admin' || actor.role === 'operator';
32	  return isOwner || isPrivileged;
33	}
34	
35	/**
36	 * Mirrors permissions.js:getPermissionsForReservation authorization (lines 91-98).
37	 * Returns true if actor may view permissions for the reservation.
38	 */
39	function isAuthorizedToViewPermissions(reservation, actor) {
40	  if (!actor) return false;
41	  const isOwner = reservation.userId === actor.id;
42	  const isPrivileged = actor.role === 'admin' || actor.role === 'operator';
43	  return isOwner || isPrivileged;
44	}
45	
46	/**
47	 * Mirrors auth-service.js:registerWithRole authorization (lines 120-124).
48	 * Returns true if actor may create users with arbitrary roles.
49	 */
50	function isAuthorizedToRegisterWithRole(actor) {
51	  if (!actor) return false;
52	  return actor.role === 'admin';
53	}
54	
55	// --------------------------------------------------------------------------
56	// Entry permission — consumeEntry cross-user denial
57	// --------------------------------------------------------------------------
58	describe('Object-Level Auth — consumeEntry', () => {
59	  const permission = { id: 1, userId: 100, reservationId: 10, status: 'active' };
60	
61	  it('should allow the permission owner to consume', () => {
62	    const actor = { id: 100, username: 'owner', role: 'visitor' };
63	    assert.equal(isAuthorizedToConsume(permission, actor), true);
64	  });
65	
66	  it('should allow an operator to consume any permission', () => {
67	    const actor = { id: 200, username: 'op', role: 'operator' };
68	    assert.equal(isAuthorizedToConsume(permission, actor), true);
69	  });
70	
71	  it('should allow an admin to consume any permission', () => {
72	    const actor = { id: 300, username: 'admin', role: 'admin' };
73	    assert.equal(isAuthorizedToConsume(permission, actor), true);
74	  });
75	
76	  it('should deny a different visitor from consuming', () => {
77	    const actor = { id: 999, username: 'other', role: 'visitor' };
78	    assert.equal(isAuthorizedToConsume(permission, actor), false);
79	  });
80	
81	  it('should deny a reviewer from consuming (not owner, not operator/admin)', () => {
82	    const actor = { id: 400, username: 'reviewer', role: 'reviewer' };
83	    assert.equal(isAuthorizedToConsume(permission, actor), false);
84	  });
85	
86	  it('should deny when no actor is provided', () => {
87	    assert.equal(isAuthorizedToConsume(permission, null), false);
88	  });
89	
90	  it('should deny when actor is undefined', () => {
91	    assert.equal(isAuthorizedToConsume(permission, undefined), false);
92	  });
93	});
94	
95	// --------------------------------------------------------------------------
96	// Entry permission — getPermissionsForReservation cross-user denial
97	// --------------------------------------------------------------------------
98	describe('Object-Level Auth — getPermissionsForReservation', () => {
99	  const reservation = { id: 10, userId: 100, zone: 'A', status: 'approved' };
100	
101	  it('should allow the reservation owner to view permissions', () => {
102	    const actor = { id: 100, username: 'owner', role: 'visitor' };
103	    assert.equal(isAuthorizedToViewPermissions(reservation, actor), true);
104	  });
105	
106	  it('should allow an operator to view any reservation permissions', () => {
107	    const actor = { id: 200, username: 'op', role: 'operator' };
108	    assert.equal(isAuthorizedToViewPermissions(reservation, actor), true);
109	  });
110	
111	  it('should allow an admin to view any reservation permissions', () => {
112	    const actor = { id: 300, username: 'admin', role: 'admin' };
113	    assert.equal(isAuthorizedToViewPermissions(reservation, actor), true);
114	  });
115	
116	  it('should deny a different visitor from viewing permissions', () => {
117	    const actor = { id: 999, username: 'other', role: 'visitor' };
118	    assert.equal(isAuthorizedToViewPermissions(reservation, actor), false);
119	  });
120	
121	  it('should deny a reviewer from viewing permissions (not owner, not operator/admin)', () => {
122	    const actor = { id: 400, username: 'reviewer', role: 'reviewer' };
123	    assert.equal(isAuthorizedToViewPermissions(reservation, actor), false);
124	  });
125	
126	  it('should deny when no actor is provided', () => {
127	    assert.equal(isAuthorizedToViewPermissions(reservation, null), false);
128	  });
129	});
