131	// --------------------------------------------------------------------------
132	// Notifications — cross-user access
133	// --------------------------------------------------------------------------
134	describe('Object-Level Auth — notification scoping', () => {
135	  it('should scope getUserNotifications to the requesting userId', () => {
136	    // getUserNotifications(userId) filters by userId via DB.getByIndex.
137	    // Passing a different userId returns that user's notifications — callers
138	    // are responsible for passing the correct userId (their own).
139	    const requestingUserId = 100;
140	    const otherUserId = 200;
141	    assert.notEqual(requestingUserId, otherUserId,
142	      'callers must pass their own userId, not another user\'s');
