145	  it('should return all notifications only when userId is falsy (admin path)', () => {
146	    // getUserNotifications(null/undefined) returns ALL notifications via getAll —
147	    // this code path should only be reachable by admins.
148	    const userId = null;
149	    assert.equal(!userId, true, 'null userId triggers the all-notifications admin path');
150	  });
151	});
152	
153	// --------------------------------------------------------------------------
154	// Auth service — registerWithRole function-level auth
155	// --------------------------------------------------------------------------
156	describe('Object-Level Auth — registerWithRole', () => {
157	  it('should allow admin to create users with any role', () => {
158	    const actor = { id: 1, username: 'admin', role: 'admin' };
159	    assert.equal(isAuthorizedToRegisterWithRole(actor), true);
160	  });
161	
162	  it('should deny visitor from creating users with roles', () => {
163	    const actor = { id: 2, username: 'visitor', role: 'visitor' };
164	    assert.equal(isAuthorizedToRegisterWithRole(actor), false);
165	  });
166	
167	  it('should deny operator from creating users with roles', () => {
168	    const actor = { id: 3, username: 'operator', role: 'operator' };
169	    assert.equal(isAuthorizedToRegisterWithRole(actor), false);
170	  });
171	
172	  it('should deny reviewer from creating users with roles', () => {
173	    const actor = { id: 4, username: 'reviewer', role: 'reviewer' };
174	    assert.equal(isAuthorizedToRegisterWithRole(actor), false);
175	  });
176	
177	  it('should deny when no actor is provided', () => {
178	    assert.equal(isAuthorizedToRegisterWithRole(null), false);
179	  });
180	
181	  it('should deny when actor is undefined', () => {
182	    assert.equal(isAuthorizedToRegisterWithRole(undefined), false);
183	  });
184	});
