1	import { describe, it, beforeEach } from 'node:test';
2	import assert from 'node:assert/strict';
3	
4	/**
5	 * Route-level authorization tests.
6	 *
7	 * The production views call requireAuth() or requireRole([...]) at the top of
8	 * their render functions. Both helpers verify the session against the DB and
9	 * redirect to /login (no session) or / (wrong role) when authorization fails.
10	 *
11	 * Since requireAuth/requireRole depend on browser globals (localStorage,
12	 * window.location, IndexedDB) we test the equivalent pure logic here:
13	 *   - Session presence and expiry checks
14	 *   - Role-gating per view
15	 *   - Fail-closed behaviour (no session, wrong role, missing user)
16	 */
17	
18	import {
19	  isSessionExpired,
20	  hasPermissionForRole,
21	  SESSION_TIMEOUT
22	} from '../frontend/js/lib/auth-logic.js';
23	
24	// Map mirrors NAV_ITEMS / route registrations in index.html
25	const ROUTE_ROLE_MAP = {
26	  '/':              ['visitor', 'operator', 'reviewer', 'admin'],
27	  '/reservations':  ['visitor', 'operator', 'admin'],
28	  '/unlock':        ['operator', 'admin'],
29	  '/map':           ['visitor', 'operator', 'reviewer', 'admin'],
30	  '/content':       ['reviewer', 'admin'],
31	  '/notifications': ['visitor', 'operator', 'reviewer', 'admin'],
32	  '/admin':         ['admin'],
33	  '/settings':      ['visitor', 'operator', 'reviewer', 'admin']
34	};
35	
36	// --------------------------------------------------------------------------
37	// requireAuth behaviour
38	// --------------------------------------------------------------------------
39	describe('Route Authorization — requireAuth', () => {
40	  it('should reject when no session exists (null)', () => {
