1	/**
2	 * Entry Permissions service.
3	 * - Permission window: 15 min before → 30 min after reservation
4	 * - Entry policy: single-use (consumed on first unlock) OR multi-use (up to 5 entries)
5	 */
6	import DB from '../database.js';
7	import { addAuditLog } from './audit.js';
8	import {
9	  calculatePermissionWindow,
10	  isWithinPermissionWindow,
11	  createPermissionObject,
12	  consumeEntry as _consumeEntry,
13	  getPermissionStatusLabel
14	} from '../lib/permissions-logic.js';
15	
16	// Re-export pure functions
17	export { calculatePermissionWindow, isWithinPermissionWindow, getPermissionStatusLabel } from '../lib/permissions-logic.js';
18	
19	export async function createEntryPermission(reservation, policy = 'single-use') {
20	  const startTime = new Date(`${reservation.date}T${reservation.time}`).getTime();
21	  const permObj = createPermissionObject(startTime, policy);
22	
23	  const permission = {
24	    ...permObj,
25	    reservationId: reservation.id,
26	    userId: reservation.userId,
27	    zone: reservation.zone,
28	    createdAt: Date.now()
29	  };
30	
31	  const id = await DB.add('entry_permissions', permission);
32	  await addAuditLog('permission_created', null, {
33	    permissionId: id,
34	    reservationId: reservation.id,
35	    policy,
36	    windowStart: new Date(permission.windowStart).toISOString(),
37	    windowEnd: new Date(permission.windowEnd).toISOString()
38	  });
39	  return { ...permission, id };
40	}
41	
42	export async function consumeEntry(permissionId, actor = null) {
43	  const perm = await DB.get('entry_permissions', permissionId);
44	  if (!perm) return { success: false, error: 'Permission not found' };
45	
46	  // Object-level authorization: only the permission owner, admin, or operator may consume
47	  if (actor) {
48	    const isOwner = perm.userId === actor.id;
49	    const isPrivileged = actor.role === 'admin' || actor.role === 'operator';
50	    if (!isOwner && !isPrivileged) {
51	      return { success: false, error: 'Not authorized to consume this entry permission' };
52	    }
53	  }
54	
55	  const before = { ...perm };
56	  const result = _consumeEntry(perm);
57	  if (!result.success) return result;
58	
59	  await DB.put('entry_permissions', perm);
60	  await addAuditLog('entry_consumed', actor?.username || null, {
61	    permissionId: perm.id,
62	    usedEntries: perm.usedEntries,
63	    maxEntries: perm.maxEntries
64	  }, before, perm);
65	
66	  return { success: true, permission: perm };
67	}
68	
69	export async function expirePermissions() {
70	  const all = await DB.getAll('entry_permissions');
71	  const now = Date.now();
72	  let expired = 0;
73	
74	  for (const perm of all) {
75	    if (perm.status === 'active' && now > perm.windowEnd) {
76	      perm.status = 'expired';
77	      await DB.put('entry_permissions', perm);
78	      expired++;
79	    }
80	  }
81	
82	  return expired;
83	}
84	
85	/**
86	 * Get all entry permissions for a reservation.
87	 * If actor is provided, verifies the actor owns the reservation or is privileged.
88	 * Returns [] (not an error) for unauthorized access to avoid leaking existence.
89	 */
90	export async function getPermissionsForReservation(reservationId, actor = null) {
91	  // Enforce actor for authorization check — callers must pass the current user
92	  if (!actor) return [];
93	  const reservation = await DB.get('reservations', reservationId);
94	  // If reservation not found, return empty to prevent orphaned permission enumeration
95	  if (!reservation) return [];
96	  const isOwner = reservation.userId === actor.id;
97	  const isPrivileged = actor.role === 'admin' || actor.role === 'operator';
98	  if (!isOwner && !isPrivileged) return [];
99	  return DB.getByIndex('entry_permissions', 'reservationId', reservationId);
100	}
