1	/**
2	 * IndexedDB wrapper for HarborGate data.
3	 * Supports encryption at rest for sensitive stores via a session-derived CryptoKey.
4	 */
5	const DB_NAME = 'harborgate';
6	const DB_VERSION = 2;
7	
8	// Stores whose records are encrypted at rest when a session key is available.
9	// NOTE: 'roles' is excluded — role definitions contain no sensitive data and
10	// must be readable pre-auth. 'users' IS included: login-critical fields
11	// (username, role, passwordHash, passwordSalt, failedAttempts, lockedUntil,
12	// banned) are preserved as plaintext alongside the encrypted payload so login
13	// can still verify credentials before the DEK is available.
14	const ENCRYPTED_STORES = new Set([
15	  'users',
16	  'reservations',
17	  'entry_permissions',
18	  'devices',
19	  'pois',
20	  'content',
21	  'reports',
22	  'audit_logs',
23	  'notifications',
24	  'command_outbox',
25	  'rate_limits',
26	  'zones',
27	  'geofences'
28	]);
29	
30	const STORES = {
31	  users: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'username', keyPath: 'username', unique: true }, { name: 'role', keyPath: 'role' }] },
32	  roles: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'name', keyPath: 'name', unique: true }] },
33	  rate_limits: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'scope', keyPath: 'scope' }, { name: 'action', keyPath: 'action' }] },
34	  reservations: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'status', keyPath: 'status' }] },
35	  entry_permissions: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'reservationId', keyPath: 'reservationId' }, { name: 'status', keyPath: 'status' }] },
36	  devices: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }, { name: 'status', keyPath: 'status' }] },
37	  pois: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }] },
38	  content: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'status', keyPath: 'status' }, { name: 'workflowState', keyPath: 'workflowState' }] },
39	  reports: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'type', keyPath: 'type' }, { name: 'status', keyPath: 'status' }] },
40	  audit_logs: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'actor', keyPath: 'actor' }, { name: 'timestamp', keyPath: 'timestamp' }, { name: 'action', keyPath: 'action' }] },
41	  notifications: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'read', keyPath: 'read' }, { name: 'scheduledFor', keyPath: 'scheduledFor' }] },
42	  command_outbox: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'status', keyPath: 'status' }, { name: 'deviceId', keyPath: 'deviceId' }] },
43	  zones: { keyPath: 'id', autoIncrement: true },
44	  geofences: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }] }
45	};
46	
47	let dbInstance = null;
48	
49	// In-memory encryption key — never persisted
50	let _encryptionKey = null;
51	
52	function setEncryptionKey(key) {
53	  _encryptionKey = key;
54	}
55	
56	function clearEncryptionKey() {
57	  _encryptionKey = null;
58	}
59	
60	function getEncryptionKey() {
61	  return _encryptionKey;
62	}
63	
64	async function encryptIfNeeded(storeName, record) {
65	  if (!_encryptionKey || !ENCRYPTED_STORES.has(storeName)) return record;
66	  try {
