170	    token,
171	    userId: user.id,
172	    username: user.username,
173	    role: user.role,
174	    createdAt: Date.now(),
175	    lastActivity: Date.now()
176	  };
177	
178	  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
179	  Store.set('session', session);
180	  Store.set('currentUser', { id: user.id, username: user.username, role: user.role });
181	
182	  startIdleTimer();
183	  await addAuditLog('user_login', username, { userId: user.id });
184	  return { success: true, session };
185	}
186	
187	function getSession() {
188	  const raw = localStorage.getItem(SESSION_KEY);
189	  if (!raw) return null;
190	  try {
191	    const session = JSON.parse(raw);
192	    if (isSessionExpired(session)) {
193	      logout();
194	      return null;
195	    }
196	    return session;
197	  } catch {
198	    return null;
199	  }
200	}
201	
202	function refreshSession() {
203	  const session = getSession();
204	  if (session) {
205	    session.lastActivity = Date.now();
206	    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
207	    Store.set('session', session);
208	    startIdleTimer();
209	    return true;
210	  }
211	  return false;
212	}
213	
214	function startIdleTimer() {
215	  clearTimeout(idleTimer);
216	  clearTimeout(warningTimer);
217	  warningTimer = setTimeout(() => {
218	    Store.set('sessionWarning', true);
219	  }, SESSION_WARNING);
220	  idleTimer = setTimeout(() => {
221	    Store.set('sessionWarning', false);
222	    Store.set('sessionExpired', true);
223	    logout();
224	  }, SESSION_TIMEOUT);
225	}
226	
227	function logout() {
228	  clearTimeout(idleTimer);
229	  clearTimeout(warningTimer);
230	  _verifiedUser = null;
231	  let session = null;
232	  try {
233	    const raw = localStorage.getItem(SESSION_KEY);
234	    if (raw) session = JSON.parse(raw);
235	  } catch (e) {}
236	  localStorage.removeItem(SESSION_KEY);
237	  Store.set('session', null);
238	  Store.set('currentUser', null);
239	  clearEncryptionKey();
240	  if (session) {
241	    addAuditLog('user_logout', session.username, { userId: session.userId });
242	  }
243	}
244	
245	function getCurrentUser() {
246	  if (_verifiedUser) return { ..._verifiedUser };
247	  // No verified user available — return null (fail closed).
248	  // Views must call requireAuth/requireRole before getCurrentUser.
249	  return null;
250	}
251	
252	function hasRole(requiredRoles) {
253	  const user = getCurrentUser();
254	  if (!user) return false;
255	  if (typeof requiredRoles === 'string') requiredRoles = [requiredRoles];
256	  return requiredRoles.includes(user.role);
257	}
258	
259	async function verifySessionUser(session) {
260	  // Authoritative lookup by immutable userId, not mutable username
261	  const user = await DB.get('users', session.userId);
262	  if (!user) return null;
263	  // Cross-check: session username must match DB record — fail closed on mismatch
264	  if (user.username !== session.username) return null;
265	  if (user.banned) return null;
266	  return user;
267	}
268	
269	async function requireAuth() {
270	  const session = getSession();
271	  if (!session) {
272	    window.location.hash = '/login';
273	    return false;
274	  }
275	  try {
276	    const user = await verifySessionUser(session);
277	    if (!user) { logout(); window.location.hash = '/login'; return false; }
278	    _verifiedUser = { id: user.id, username: user.username, role: user.role };
279	  } catch {
280	    // DB unavailable — fail closed: do not authorize from unverified session
281	    logout();
282	    window.location.hash = '/login';
283	    return false;
284	  }
285	  refreshSession();
286	  return true;
287	}
288	
289	async function requireRole(roles) {
290	  const session = getSession();
291	  if (!session) {
292	    window.location.hash = '/login';
293	    return false;
294	  }
295	  if (typeof roles === 'string') roles = [roles];
296	  try {
297	    const user = await verifySessionUser(session);
298	    if (!user) {
299	      logout();
300	      window.location.hash = '/login';
301	      return false;
302	    }
303	    _verifiedUser = { id: user.id, username: user.username, role: user.role };
304	    if (!roles.includes(user.role)) {
305	      window.location.hash = '/';
306	      return false;
307	    }
308	  } catch {
309	    // DB unavailable — fail closed: do not authorize from unverified session
310	    logout();
311	    window.location.hash = '/login';
312	    return false;
313	  }
314	  refreshSession();
315	  return true;
316	}
317	
318	async function initRoles() {
319	  const existing = await DB.getAll('roles');
320	  if (existing.length > 0) return;
321	  for (const role of ROLE_DEFINITIONS) {
322	    await DB.add('roles', role);
323	  }
324	}
325	
326	async function needsSetup() {
327	  const users = await DB.getAll('users');
328	  return users.length === 0;
329	}
330	
331	async function setupAdmin(username, password) {
332	  const users = await DB.getAll('users');
333	  if (users.length > 0) return { success: false, errors: ['Setup already completed'] };
334	  // Bootstrap path: no actor exists yet, use internal helper directly
335	  return _createUserWithRole(username, password, 'admin', 'system');
336	}
337	
338	function hasPermission(permission) {
339	  const user = getCurrentUser();
340	  if (!user) return false;
341	  return hasPermissionForRole(user.role, permission);
342	}
343	
344	async function loadRoles() {
345	  const roles = await DB.getAll('roles');
346	  Store.set('roles', roles);
347	  return roles;
348	}
349	
350	export {
351	  validatePassword,
352	  isAccountLocked,
353	  register,
354	  registerWithRole,
355	  login,
356	  getSession,
357	  refreshSession,
358	  startIdleTimer,
359	  logout,
360	  getCurrentUser,
361	  hasRole,
362	  requireAuth,
363	  requireRole,
364	  initRoles,
365	  needsSetup,
366	  setupAdmin,
367	  hasPermission,
368	  loadRoles
369	};
